/**
 * gen_agents_context tool
 *
 * Writes a managed, auto-generated block into a convention file (AGENTS.md by
 * default, also CLAUDE.md / GEMINI.md / .cursorrules) containing the
 * anti-hallucination rules, the repeat-offender watchlist, and a compact map of
 * the project's key symbols and API routes.
 *
 * This is the model-agnostic distribution path: any agent that reads these
 * convention files (Claude Code, Codex, Cursor, Gemini, Copilot, …) gets the
 * anti-hallucination guardrails without needing the MCP server or hooks wired.
 */

import fs from 'fs';
import path from 'path';
import { findProjectRoot, getWisdomDir } from '../lib/wisdom.js';
import { readSymbols } from '../lib/indexer.js';
import { getHallucinationPatterns } from '../lib/hallucination-tracker.js';

const BEGIN = '<!-- ANTI-HALLUCINATION:BEGIN (auto-generated — do not edit by hand) -->';
const END = '<!-- ANTI-HALLUCINATION:END -->';

const CORE_RULES = [
  'NEVER assume a symbol exists — verify it (check_symbols, get_file_skeleton, or read the file) before using it.',
  'NEVER assume a file path — confirm the file exists before importing from it.',
  'NEVER assume an API route — check the actual router/handler.',
  'When unsure, READ the source. Reading is always cheaper than hallucinating.'
];

export function buildManagedBlock(registry, patterns, options = {}) {
  const topExports = options.maxExports || 40;
  const lines = [BEGIN];
  lines.push('## 🛡️ Anti-Hallucination Guardrails');
  lines.push('');
  lines.push('Generated by [Anti-Hallucination-MCP](https://github.com/Akunimal/Anti-Hallucination-MCP). Re-run `gen_agents_context` (or `anti-hallucination agents`) to refresh.');
  lines.push('');
  for (const rule of CORE_RULES) lines.push(`- ${rule}`);

  if (patterns && patterns.frequent && patterns.frequent.length > 0) {
    lines.push('');
    lines.push('### ⚠️ Watchlist — previously hallucinated in this repo (verify before use)');
    const items = patterns.frequent.slice(0, 15).map((p) => `\`${p.symbol}\` (×${p.count})`);
    lines.push(items.join(', '));
  }

  if (registry) {
    const cat = (c) => (registry[c] && typeof registry[c] === 'object' ? Object.keys(registry[c]) : []);
    const funcs = cat('functions');
    const classes = cat('classes');
    const exportsList = cat('exports');
    const routes = cat('apiRoutes');

    lines.push('');
    lines.push('### Symbol map');
    lines.push(`- Functions: ${funcs.length} · Classes/Types: ${classes.length} · Exports: ${exportsList.length} · API routes: ${routes.length}`);

    if (exportsList.length > 0) {
      const shown = exportsList.slice(0, topExports);
      lines.push(`- Key exports: ${shown.join(', ')}${exportsList.length > shown.length ? `, … +${exportsList.length - shown.length} more` : ''}`);
    }
    if (routes.length > 0) {
      const shown = routes.slice(0, 30);
      lines.push(`- API routes: ${shown.join(' · ')}${routes.length > shown.length ? ` · … +${routes.length - shown.length} more` : ''}`);
    }
  } else {
    lines.push('');
    lines.push('_No symbol registry yet — run `reindex_project` (or `anti-hallucination index`) to populate the symbol map._');
  }

  lines.push(END);
  return lines.join('\n');
}

function upsertManagedBlock(existing, block) {
  if (existing && existing.includes(BEGIN) && existing.includes(END)) {
    return existing.replace(new RegExp(`${escapeRe(BEGIN)}[\\s\\S]*?${escapeRe(END)}`), block);
  }
  const base = existing ? existing.trimEnd() + '\n\n' : '';
  return base + block + '\n';
}

function escapeRe(s) {
  return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

export const genAgentsContextDefinition = {
  name: 'gen_agents_context',
  description: 'Writes a managed anti-hallucination block (rules + repeat-offender watchlist + key symbols/routes) into a convention file (AGENTS.md by default). Any agent that reads these files — Claude Code, Codex, Cursor, Gemini, Copilot — then gets the guardrails without the MCP server or hooks. Idempotent: re-running updates the block in place.',
  inputSchema: {
    type: 'object',
    properties: {
      project_path: { type: 'string', description: 'Project root. Auto-detected if omitted.' },
      target: { type: 'string', description: 'Convention file to write, relative to the project root. Default: AGENTS.md.', default: 'AGENTS.md' }
    },
    required: []
  }
};

export async function handleGenAgentsContext(args = {}) {
  const projectRoot = findProjectRoot(args.project_path);
  const target = args.target || 'AGENTS.md';
  const targetPath = path.join(projectRoot, target);

  const wisdomDir = getWisdomDir(projectRoot);
  let registry = null;
  let patterns = { frequent: [] };
  try { registry = readSymbols(wisdomDir); } catch { /* none yet */ }
  try { patterns = getHallucinationPatterns(wisdomDir); } catch { /* none yet */ }

  const block = buildManagedBlock(registry, patterns);

  let existing = null;
  try { existing = fs.readFileSync(targetPath, 'utf8'); } catch { /* new file */ }
  const next = upsertManagedBlock(existing, block);

  try {
    fs.writeFileSync(targetPath, next);
  } catch (e) {
    return { content: [{ type: 'text', text: `Failed to write ${target}: ${e.message}` }], isError: true };
  }

  const action = existing && existing.includes(BEGIN) ? 'Updated' : 'Wrote';
  const watch = patterns.frequent.length;
  return {
    content: [{ type: 'text', text: `${action} anti-hallucination block in ${target}${registry ? '' : ' (no registry yet — run reindex first)'}${watch ? ` · ${watch} watchlist symbol(s)` : ''}. Agents that read ${target} now share the guardrails.` }]
  };
}
